import{_ as a,o as t,c as o,ag as s}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"AI Chat","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai-chat.md","filePath":"guide/ai-chat.md","lastUpdated":1772692870000}'),r={name:"guide/ai-chat.md"};function i(n,e,l,h,c,d){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="ai-chat" tabindex="-1">AI Chat <a class="header-anchor" href="#ai-chat" aria-label="Permalink to &quot;AI Chat&quot;">​</a></h1><p>The AI Chat panel lets you have a conversation about your lab results with an AI that already knows everything about your data — your biomarker history, lifestyle context, supplements, notes, and health goals.</p><h2 id="opening-the-chat" tabindex="-1">Opening the Chat <a class="header-anchor" href="#opening-the-chat" aria-label="Permalink to &quot;Opening the Chat&quot;">​</a></h2><p>Click the <strong>chat bubble</strong> in the bottom-right corner of the screen to slide the chat panel open. You can also click the <strong>Ask AI</strong> button in the header. Press <strong>Escape</strong> to close it.</p><div class="tip custom-block"><p class="custom-block-title">Chat FAB</p><p>The floating chat bubble (FAB) is always visible in the bottom-right corner, giving you one-tap access to the AI from any screen.</p></div><h2 id="setup-guide" tabindex="-1">Setup Guide <a class="header-anchor" href="#setup-guide" aria-label="Permalink to &quot;Setup Guide&quot;">​</a></h2><p>If no AI provider is configured, the chat panel shows a setup guide instead of the conversation view. The guide explains your provider options and includes a <strong>Connect with OpenRouter</strong> button for one-click OAuth setup — no API key needed. Once connected, the chat is ready immediately.</p><h2 id="what-the-ai-knows" tabindex="-1">What the AI Knows <a class="header-anchor" href="#what-the-ai-knows" aria-label="Permalink to &quot;What the AI Knows&quot;">​</a></h2><p>Every message you send includes a full snapshot of your data:</p><ul><li>All lab values across every draw date, with reference ranges and trend direction</li><li>Your nine <a href="/docs/guide/context-cards.html">Context Cards</a> (diet, sleep, exercise, environment, etc.)</li><li>Your <a href="/docs/guide/interpretive-lens.html">Interpretive Lens</a> and <a href="/docs/guide/health-goals.html">Health Goals</a></li><li>Your supplements and their date ranges</li><li>Your notes</li><li>For female profiles: menstrual cycle data and phase context</li></ul><p>You do not need to paste your results into the chat. Just ask your question.</p><h2 id="active-model-display" tabindex="-1">Active Model Display <a class="header-anchor" href="#active-model-display" aria-label="Permalink to &quot;Active Model Display&quot;">​</a></h2><p>The chat header shows the name of your currently active AI model, so you always know which model is responding. Each message also includes a cost footnote showing the estimated token cost for that exchange.</p><h2 id="personalities" tabindex="-1">Personalities <a class="header-anchor" href="#personalities" aria-label="Permalink to &quot;Personalities&quot;">​</a></h2><p>The AI adopts a personality that shapes its communication style. Choose from three:</p><h3 id="default" tabindex="-1">Default <a class="header-anchor" href="#default" aria-label="Permalink to &quot;Default&quot;">​</a></h3><p>A clear, evidence-informed tone. Explains markers plainly, notes trends, and flags concerns without drama.</p><h3 id="house" tabindex="-1">House <a class="header-anchor" href="#house" aria-label="Permalink to &quot;House&quot;">​</a></h3><p>Takes on the style of a sharp, skeptical clinician who asks uncomfortable questions. Pushes back on assumptions and digs for root causes.</p><h3 id="custom" tabindex="-1">Custom <a class="header-anchor" href="#custom" aria-label="Permalink to &quot;Custom&quot;">​</a></h3><p>Create your own persona. Type a name in the custom personality field and click <strong>Generate</strong> — the AI will create a full personality profile for that persona, including communication style, analytical approach, and philosophical lens. You can edit the generated text before saving.</p><p>The <strong>Enforce evidence-based accuracy</strong> option (off by default) adds a strict disclaimer to the AI&#39;s instructions, keeping responses grounded in published research rather than speculation.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Custom personalities are saved per profile and persist across sessions. You can create a persona based on a specific medical philosophy, a fictional doctor character, or any style that makes conversations more useful for you.</p></div><h2 id="conversation-threads" tabindex="-1">Conversation Threads <a class="header-anchor" href="#conversation-threads" aria-label="Permalink to &quot;Conversation Threads&quot;">​</a></h2><p>The chat panel includes a <strong>thread rail</strong> on the left side — a list of your past conversations. Each thread is named automatically from your first message, and you can rename any thread by clicking its name.</p><ul><li>Start a new conversation at any time</li><li>Switch between threads without losing history</li><li>Up to 50 threads are stored per profile; the oldest are pruned automatically</li></ul><p>On mobile, tap the hamburger icon in the chat header to open the thread list, and use the back button to return to the conversation.</p><h2 id="per-marker-ai-explanations" tabindex="-1">Per-Marker AI Explanations <a class="header-anchor" href="#per-marker-ai-explanations" aria-label="Permalink to &quot;Per-Marker AI Explanations&quot;">​</a></h2><p>From any marker&#39;s detail view (click a marker name in the sidebar or on the dashboard), you will find an <strong>Ask AI</strong> button. This opens a pre-populated chat asking the AI to explain that specific marker in the context of your results — without you having to type anything.</p><h2 id="markdown-responses" tabindex="-1">Markdown Responses <a class="header-anchor" href="#markdown-responses" aria-label="Permalink to &quot;Markdown Responses&quot;">​</a></h2><p>The AI&#39;s responses are rendered with full markdown formatting:</p><ul><li>Headings, bold, and italic text</li><li>Bullet and numbered lists</li><li>Code blocks and inline code</li><li>Clickable links</li></ul><p>Responses stream in word by word as the AI generates them.</p><h2 id="choosing-a-provider" tabindex="-1">Choosing a Provider <a class="header-anchor" href="#choosing-a-provider" aria-label="Permalink to &quot;Choosing a Provider&quot;">​</a></h2><p>The AI chat works with any of the four supported providers: Anthropic, OpenRouter, Venice, or Local AI. See <a href="/docs/guide/ai-providers.html">AI Providers</a> to configure your key or local server. The chat is not available until a provider is set up.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Conversations are stored locally in your browser and encrypted if you have set a passphrase. The last 10 messages from each conversation are sent to the AI provider with every request to maintain context. Your provider&#39;s privacy policy applies to that data.</p></div>',36)])])}const m=a(r,[["render",i]]);export{u as __pageData,m as default};
